(function(){function queryString(){var i=0,queryObj={},pair;var queryStr=window.location.search.substring(1);var queryArr=queryStr.split("&");for(i=0;i<queryArr.length;i++){pair=queryArr[i].split("=");if(typeof queryObj[pair[0]]==="undefined"){queryObj[pair[0]]=pair[1]}else if(typeof queryObj[pair[0]]==="string"){queryObj[pair[0]]=[queryObj[pair[0]],pair[1]]}else{queryObj[pair[0]].push(pair[1])}}return queryObj}var setUrlQuery=function(){var baseUrl=window.location.href.split("?")[0];return function(query){if(typeof query==="string"){window.history.replaceState(null,"",baseUrl+query)}else{window.history.replaceState(null,"",baseUrl)}}}();document.addEventListener("DOMContentLoaded",function(){var tags=document.querySelector(".js-tags");if(!tags)return;var articleTags=tags.querySelectorAll(".tag-button");var tagShowAll=tags.querySelector(".tag-button--all");var result=document.querySelector(".js-result");if(!result)return;var sections=result.querySelectorAll("section");var sectionArticles=[];var lastFocusButton=null;var hasInit=false;sections.forEach(function(section){sectionArticles.push(section.querySelectorAll(".item"))});function tagSelect(tag,target){var resultMap={};var i,j,k;for(i=0;i<sectionArticles.length;i++){for(j=0;j<sectionArticles[i].length;j++){if(tag===""||tag===undefined){resultMap[i]||(resultMap[i]={});resultMap[i][j]=true}else{var itemTags=sectionArticles[i][j].getAttribute("data-tags");if(itemTags){var tagArr=itemTags.split(",");for(k=0;k<tagArr.length;k++){if(tagArr[k]===tag){resultMap[i]||(resultMap[i]={});resultMap[i][j]=true;break}}}}}}for(i=0;i<sectionArticles.length;i++){var sectionHasVisible=false;for(j=0;j<sectionArticles[i].length;j++){if(resultMap[i]&&resultMap[i][j]){sectionArticles[i][j].classList.remove("item-hidden");sectionHasVisible=true}else{sectionArticles[i][j].classList.add("item-hidden")}}if(sectionHasVisible){sections[i].classList.remove("section-hidden")}else{sections[i].classList.add("section-hidden")}}if(!hasInit){result.classList.remove("archive-hidden");result.classList.add("archive-visible");hasInit=true}if(target){if(lastFocusButton&&lastFocusButton!==target){lastFocusButton.classList.remove("focus")}target.classList.add("focus");lastFocusButton=target;var _tag=target.getAttribute("data-encode");if(!_tag||_tag===""){setUrlQuery()}else{setUrlQuery("?tag="+_tag)}}else{if(!_tag){if(tagShowAll){if(lastFocusButton&&lastFocusButton!==tagShowAll)lastFocusButton.classList.remove("focus");tagShowAll.classList.add("focus");lastFocusButton=tagShowAll}}else{var btn=tags.querySelector('.tag-button[data-encode="'+tag+'"]');if(btn){if(lastFocusButton&&lastFocusButton!==btn)lastFocusButton.classList.remove("focus");btn.classList.add("focus");lastFocusButton=btn}}}}var query=queryString();var _tag=query.tag;tagSelect(_tag);tags.addEventListener("click",function(e){var link=e.target.closest("a");if(link){e.preventDefault();tagSelect(link.getAttribute("data-encode"),link)}})})})();